def normalize_rel_preview_path(path_text: str) -> str:
    raw = str(path_text or "").strip().replace("\\", "/")
    if not raw:
        return ""
    try:
        p = PurePosixPath(raw)
        parts = [seg for seg in p.parts if seg not in ("", ".")]
        if not parts:
            return ""
        return PurePosixPath(*parts).as_posix()
    except Exception:
        return raw.lstrip("/")

def is_code_preview_candidate(path_text: str) -> bool:
    rel = normalize_rel_preview_path(path_text).lower()
    if not rel:
        return False
    name = PurePosixPath(rel).name.lower()
    ext = PurePosixPath(rel).suffix.lower()
    if ext in CODE_PREVIEW_EXTS:
        return True
    return name in CODE_PREVIEW_FILENAMES

def preview_kind_for_path(path_text: str) -> str:
    rel = normalize_rel_preview_path(path_text).lower()
    if not rel:
        return ""
    if rel.endswith((".html", ".htm")):
        return "html"
    if rel.endswith((".md", ".markdown")):
        return "markdown"
    if is_code_preview_candidate(rel):
        return "code"
    return ""

